import websockets
from dataclasses import dataclass, field
from typing import Optional
from enum import Enum


class ItemRarity(Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    value: int
    owner_id: Optional[str] = None
    locked: bool = False  # Whether item is locked in a pending trade

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "value": self.value,
            "owner_id": self.owner_id,
            "locked": self.locked,
        }


@dataclass
class Player:
    player_id: str
    username: str
    inventory: dict = field(default_factory=dict)  # item_id -> Item
    gold: int = 1000
    websocket: Optional[object] = None
    pending_trades: set = field(default_factory=set)

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "username": self.username,
            "gold": self.gold,
            "inventory": {k: v.to_dict() for k, v in self.inventory.items()},
        }


class TradeState(Enum):
    PENDING = "pending"
    ACCEPTED = "accepted"
    DECLINED = "declined"
    COMPLETED = "completed"
    CANCELLED = "cancelled"


@dataclass
class TradeOffer:
    trade_id: str
    initiator_id: str
    receiver_id: str
    initiator_items: list = field(default_factory=list)  # list of item_ids
    receiver_items: list = field(default_factory=list)   # list of item_ids
    initiator_gold: int = 0
    receiver_gold: int = 0
    state: TradeState = TradeState.PENDING
    initiator_confirmed: bool = False
    receiver_confirmed: bool = False
    version: int = 0  # Optimistic concurrency control version


class GameServer:
    def __init__(self):
        self.players: dict[str, Player] = {}
        self.items: dict[str, Item] = {}
        self.trades: dict[str, TradeOffer] = {}
        self.connections: dict[str, websockets.WebSocketServerProtocol] = {}

        # Fine-grained locks to prevent duplication and race conditions
        self._player_locks: dict[str, asyncio.Lock] = {}
        self._item_locks: dict[str, asyncio.Lock] = {}
        self._trade_locks: dict[str, asyncio.Lock] = {}
        self._global_trade_lock = asyncio.Lock()  # For trade creation/lookup
        self._item_registry_lock = asyncio.Lock()  # For item creation

        # Transaction log for audit trail
        self._transaction_log: list[dict] = []

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self._player_locks:
            self._player_locks[player_id] = asyncio.Lock()
        return self._player_locks[player_id]

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        if item_id not in self._item_locks:
            self._item_locks[item_id] = asyncio.Lock()
        return self._item_locks[item_id]

    def _get_trade_lock(self, trade_id: str) -> asyncio.Lock:
        if trade_id not in self._trade_locks:
            self._trade_locks[trade_id] = asyncio.Lock()
        return self._trade_locks[trade_id]

    def _log_transaction(self, action: str, details: dict):
        entry = {
            "transaction_id": str(uuid.uuid4()),
            "action": action,
            "details": details,
        }
        self._transaction_log.append(entry)
        print(f"[TRANSACTION LOG] {action}: {json.dumps(details, default=str)}")

    async def _create_starter_items(self, player_id: str):
        """Give new players some starter items."""
        starter_items = [
            ("Wooden Sword", ItemRarity.COMMON, 10),
            ("Leather Armor", ItemRarity.COMMON, 15),
            ("Health Potion", ItemRarity.COMMON, 5),
            ("Iron Shield", ItemRarity.UNCOMMON, 50),
        ]
        async with self._item_registry_lock:
            for name, rarity, value in starter_items:
                item_id = str(uuid.uuid4())
                item = Item(
                    item_id=item_id,
                    name=name,
                    rarity=rarity,
                    value=value,
                    owner_id=player_id,
                )
                self.items[item_id] = item
                self.players[player_id].inventory[item_id] = item
                self._item_locks[item_id] = asyncio.Lock()

    async def handle_login(self, websocket, data: dict) -> dict:
        username = data.get("username", "").strip()
        if not username:
            return {"type": "error", "message": "Username required"}

        # Check if username already connected
        for pid, player in self.players.items():
            if player.username == username and player.websocket is not None:
                return {"type": "error", "message": "Username already connected"}

        # Find existing player or create new
        existing_player = None
        for pid, player in self.players.items():
            if player.username == username:
                existing_player = player
                break

        if existing_player:
            player_id = existing_player.player_id
            existing_player.websocket = websocket
        else:
            player_id = str(uuid.uuid4())
            player = Player(
                player_id=player_id,
                username=username,
                websocket=websocket,
            )
            self.players[player_id] = player
            self._player_locks[player_id] = asyncio.Lock()
            await self._create_starter_items(player_id)

        self.connections[player_id] = websocket

        self._log_transaction("LOGIN", {"player_id": player_id, "username": username})

        # Notify other players
        await self._broadcast(
            {
                "type": "player_joined",
                "player_id": player_id,
                "username": username,
            },
            exclude=player_id,
        )

        return {
            "type": "login_success",
            "player": self.players[player_id].to_dict(),
            "online_players": [
                {"player_id": p.player_id, "username": p.username}
                for p in self.players.values()
                if p.websocket is not None and p.player_id != player_id
            ],
        }

    async def handle_get_inventory(self, player_id: str) -> dict:
        player = self.players.get(player_id)
        if not player:
            return {"type": "error", "message": "Player not found"}

        return {
            "type": "inventory",
            "inventory": {k: v.to_dict() for k, v in player.inventory.items()},
            "gold": player.gold,
        }

    async def handle_initiate_trade(self, player_id: str, data: dict) -> dict:
        target_id = data.get("target_player_id")
        if not target_id or target_id not in self.players:
            return {"type": "error", "message": "Target player not found"}

        if target_id == player_id:
            return {"type": "error", "message": "Cannot trade with yourself"}

        target = self.players[target_id]
        if target.websocket is None:
            return {"type": "error", "message": "Target player is offline"}

        async with self._global_trade_lock:
            # Check neither player is already in an active trade
            for trade in self.trades.values():
                if trade.state == TradeState.PENDING:
                    if trade.initiator_id == player_id or trade.receiver_id == player_id:
                        return {"type": "error", "message": "You already have a pending trade"}
                    if trade.initiator_id == target_id or trade.receiver_id == target_id:
                        return {"type": "error", "message": "Target player already has a pending trade"}

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                initiator_id=player_id,
                receiver_id=target_id,
            )
            self.trades[trade_id] = trade
            self._trade_locks[trade_id] = asyncio.Lock()

        self._log_transaction("TRADE_INITIATED", {
            "trade_id": trade_id,
            "initiator": player_id,
            "receiver": target_id,
        })

        # Notify the target player
        await self._send_to_player(target_id, {
            "type": "trade_request",
            "trade_id": trade_id,
            "from_player_id": player_id,
            "from_username": self.players[player_id].username,
        })

        return {
            "type": "trade_initiated",
            "trade_id": trade_id,
            "target_player_id": target_id,
        }

    async def handle_trade_response(self, player_id: str, data: dict) -> dict:
        trade_id = data.get("trade_id")
        accept = data.get("accept", False)

        if not trade_id or trade_id not in self.trades:
            return {"type": "error", "message": "Trade not found"}

        async with self._get_trade_lock(trade_id):
            trade = self.trades[trade_id]

            if trade.receiver_id != player_id:
                return {"type": "error", "message": "Not your trade to respond to"}

            if trade.state != TradeState.PENDING:
                return {"type": "error", "message": "Trade is no longer pending"}

            if accept:
                trade.state = TradeState.ACCEPTED
                self._log_transaction("TRADE_ACCEPTED", {"trade_id": trade_id})

                await self._send_to_player(trade.initiator_id, {
                    "type": "trade_accepted",
                    "trade_id": trade_id,
                })

                return {
                    "type": "trade_accepted",
                    "trade_id": trade_id,
                }
            else:
                trade.state = TradeState.DECLINED
                self._log_transaction("TRADE_DECLINED", {"trade_id": trade_id})

                await self._send_to_player(trade.initiator_id, {
                    "type": "trade_declined",
                    "trade_id": trade_id,
                })

                return {
                    "type": "trade_declined",
                    "trade_id": trade_id,
                }

    async def handle_update_trade_offer(self, player_id: str, data: dict) -> dict:
        trade_id = data.get("trade_id")
        offered_items = data.get("items", [])
        offered_gold = data.get("gold", 0)

        if not trade_id or trade_id not in self.trades:
            return {"type": "error", "message": "Trade not found"}

        if not isinstance(offered_gold, int) or offered_gold < 0:
            return {"type": "error", "message": "Invalid gold amount"}

        async with self._get_trade_lock(trade_id):
            trade = self.trades[trade_id]

            if trade.state != TradeState.ACCEPTED:
                return {"type": "error", "message": "Trade is not in accepted state"}

            if player_id not in (trade.initiator_id, trade.receiver_id):
                return {"type": "error", "message": "Not part of this trade"}

            # Reset confirmations when offer changes
            trade.initiator_confirmed = False
            trade.receiver_confirmed = False
            trade.version += 1

            player = self.players[player_id]

            # Validate items belong to the player and are not locked by another trade
            validated_items = []
            for item_id in offered_items:
                if item_id not in player.inventory:
                    return {"type": "error", "message": f"Item {item_id} not in your inventory"}
                item = player.inventory[item_id]
                if item.locked and item_id not in (
                    trade.initiator_items if player_id == trade.initiator_id else trade.receiver_items
                ):
                    return {"type": "error", "message": f"Item {item_id} is locked in another trade"}
                validated_items.append(item_id)

            # Validate gold
            if offered_gold > player.gold:
                return {"type": "error", "message": "Insufficient gold"}

            # Unlock previously offered items
            if player_id == trade.initiator_id:
                for old_item_id in trade.initiator_items:
                    if old_item_id in self.items:
                        self.items[old_item_id].locked = False
                trade.initiator_items = validated_items
                trade.initiator_gold = offered_gold
            else:
                for old_item_id in trade.receiver_items:
                    if old_item_id in self.items:
                        self.items[old_item_id].locked = False
                trade.receiver_items = validated_items
                trade.receiver_gold = offered_gold

            # Lock newly offered items
            for item_id in validated_items:
                self.items[item_id].locked = True

            # Notify the other party
            other_id = trade.receiver_id if player_id == trade.initiator_id else trade.initiator_id
            await self._send_to_player(other_id, {
                "type": "trade_offer_updated",
                "trade_id": trade_id,
                "player_id": player_id,
                "items": [self.items[iid].to_dict() for iid in validated_items],
                "gold": offered_gold,
                "version": trade.version,
            })

            return {
                "type": "trade_offer_updated",
                "trade_id": trade_id,
                "your_items": [self.items[iid].to_dict() for iid in validated_items],
                "your_gold": offered_gold,
                "version": trade.version,
            }

    async def handle_confirm_trade(self, player_id: str, data: dict) -> dict:
        trade_id = data.get("trade_id")
        expected_version = data.get("version")

        if not trade_id or trade_id not in self.trades:
            return {"type": "error", "message": "Trade not found"}

        async with self._get_trade_lock(trade_id):
            trade = self.trades[trade_id]

            if trade.state != TradeState.ACCEPTED:
                return {"type": "error", "message": "Trade is not in accepted state"}

            if player_id not in (trade.initiator_id, trade.receiver_id):
                return {"type": "error", "message": "Not part of this trade"}

            # Optimistic concurrency check
            if expected_version is not None and expected_version != trade.version:
                return {
                    "type": "error",
                    "message": "Trade offer has changed since you last viewed it. Please review.",
                    "current_version": trade.version,
                }

            if player_id == trade.initiator_id:
                trade.initiator_confirmed = True
            else:
                trade.receiver_confirmed = True

            other_id = trade.receiver_id if player_id == trade.initiator_id else trade.initiator_id

            if trade.initiator_confirmed and trade.receiver_confirmed:
                # Execute the trade atomically
                result = await self._execute_trade(trade)
                if result["success"]:
                    trade.state = TradeState.COMPLETED

                    await self._send_to_player(trade.initiator_id, {
                        "type": "trade_completed",
                        "trade_id": trade_id,
                        "details": result["details"],
                    })
                    await self._send_to_player(trade.receiver_id, {
                        "type": "trade_completed",
                        "trade_id": trade_id,
                        "details": result["details"],
                    })

                    return {
                        "type": "trade_completed",
                        "trade_id": trade_id,
                        "details": result["details"],
                    }
                else:
                    # Rollback confirmations
                    trade.initiator_confirmed = False
                    trade.receiver_confirmed = False
                    return {"type": "error", "message": result["error"]}
            else:
                await self._send_to_player(other_id, {
                    "type": "trade_player_confirmed",
                    "trade_id": trade_id,
                    "player_id": player_id,
                })

                return {
                    "type": "trade_confirmed",
                    "trade_id": trade_id,
                    "waiting_for_other": True,
                }

    async def _execute_trade(self, trade: TradeOffer) -> dict:
        """
        Execute the trade atomically. Acquire locks on both players in a
        consistent order (sorted by player_id) to prevent deadlocks.
        Then validate and transfer items.
        """
        player_ids = sorted([trade.initiator_id, trade.receiver_id])

        async with self._get_player_lock(player_ids[0]):
            async with self._get_player_lock(player_ids[1]):
                initiator = self.players[trade.initiator_id]
                receiver = self.players[trade.receiver_id]

                # === VALIDATION PHASE ===
                # Re-validate all items still belong to correct owners and are locked for this trade
                for item_id in trade.initiator_items:
                    if item_id not in initiator.inventory:
                        return {"success": False, "error": f"Initiator no longer owns item {item_id}"}
                    item = initiator.inventory[item_id]
                    if item.owner_id != trade.initiator_id:
                        return {"success": False, "error": f"Item {item_id} ownership mismatch"}
                    if not item.locked:
                        return {"success": False, "error": f"Item {item_id} is not locked for trade"}

                for item_id in trade.receiver_items:
                    if item_id not in receiver.inventory:
                        return {"success": False, "error": f"Receiver no longer owns item {item_id}"}
                    item = receiver.inventory[item_id]
                    if item.owner_id != trade.receiver_id:
                        return {"success": False, "error": f"Item {item_id} ownership mismatch"}
                    if not item.locked:
                        return {"success": False, "error": f"Item {item_id} is not locked for trade"}

                # Validate gold
                if trade.initiator_gold > initiator.gold:
                    return {"success": False, "error": "Initiator has insufficient gold"}
                if trade.receiver_gold > receiver.gold:
                    return {"success": False, "error": "Receiver has insufficient gold"}

                # === TRANSFER PHASE ===
                # Transfer items from initiator to receiver
                for item_id in trade.initiator_items:
                    item = initiator.inventory.pop(item_id)
                    item.owner_id = trade.receiver_id
                    item.locked = False
                    receiver.inventory[item_id] = item

                # Transfer items from receiver to initiator
                for item_id in trade.receiver_items:
                    item = receiver.inventory.pop(item_id)
                    item.owner_id = trade.initiator_id
                    item.locked = False
                    initiator.inventory[item_id] = item

                # Transfer gold
                initiator.gold -= trade.initiator_gold
                initiator.gold += trade.receiver_gold
                receiver.gold -= trade.receiver_gold
                receiver.gold += trade.initiator_gold

                # Integrity check: ensure no item duplication
                all_item_ids = set()
                for player in self.players.values():
                    for item_id in player.inventory:
                        if item_id in all_item_ids:
                            # CRITICAL: Item duplication detected - this should never happen
                            self._log_transaction("CRITICAL_DUPLICATION_DETECTED", {
                                "trade_id": trade.trade_id,
                                "duplicated_item": item_id,
                            })
                            # In production, you'd want to halt and investigate
                            return {"success": False, "error": "Critical integrity error detected"}
                        all_item_ids.add(item_id)

                details = {
                    "initiator_gave_items": trade.initiator_items,
                    "receiver_gave_items": trade.receiver_items,
                    "initiator_gave_gold": trade.initiator_gold,
                    "receiver_gave_gold": trade.receiver_gold,
                }

                self._log_transaction("TRADE_EXECUTED", {
                    "trade_id": trade.trade_id,
                    "initiator": trade.initiator_id,
                    "receiver": trade.receiver_id,
                    **details,
                })

                return {"success": True, "details": details}

    async def handle_cancel_trade(self, player_id: str, data: dict) -> dict:
        trade_id = data.get("trade_id")

        if not trade_id or trade_id not in self.trades:
            return {"type": "error", "message": "Trade not found"}

        async with self._get_trade_lock(trade_id):
            trade = self.trades[trade_id]

            if player_id not in (trade.initiator_id, trade.receiver_id):
                return {"type": "error", "message": "Not part of this trade"}

            if trade.state in (TradeState.COMPLETED, TradeState.CANCELLED):
                return {"type": "error", "message": "Trade already finalized"}

            trade.state = TradeState.CANCELLED

            # Unlock all items
            for item_id in trade.initiator_items + trade.receiver_items:
                if item_id in self.items:
                    self.items[item_id].locked = False

            self._log_transaction("TRADE_CANCELLED", {
                "trade_id": trade_id,
                "cancelled_by": player_id,
            })

            other_id = trade.receiver_id if player_id == trade.initiator_id else trade.initiator_id
            await self._send_to_player(other_id, {
                "type": "trade_cancelled",
                "trade_id": trade_id,
                "cancelled_by": player_id,
            })

            return {
                "type": "trade_cancelled",
                "trade_id": trade_id,
            }

    async def handle_transfer_item(self, player_id: str, data: dict) -> dict:
        """Direct item transfer (e.g., dropping item to another player, gifting)."""
        item_id = data.get("item_id")
        target_id = data.get("target_player_id")

        if not item_id or not target_id:
            return {"type": "error", "message": "item_id and target_player_id required"}

        if target_id not in self.players:
            return {"type": "error", "message": "Target player not found"}

        if player_id == target_id:
            return {"type": "error", "message": "Cannot transfer to yourself"}

        # Lock in consistent order to prevent deadlocks
        ordered_ids = sorted([player_id, target_id])

        async with self._get_player_lock(ordered_ids[0]):
            async with self._get_player_lock(ordered_ids[1]):
                source = self.players[player_id]
                target = self.players[target_id]

                if item_id not in source.inventory:
                    return {"type": "error", "message": "Item not in your inventory"}

                item = source.inventory[item_id]

                if item.locked:
                    return {"type": "error", "message": "Item is locked in a pending trade"}

                if item.owner_id != player_id:
                    return {"type": "error", "message": "Item ownership mismatch"}

                # Execute transfer
                del source.inventory[item_id]
                item.owner_id = target_id
                target.inventory[item_id] = item

                self._log_transaction("DIRECT_TRANSFER", {
                    "item_id": item_id,
                    "from": player_id,
                    "to": target_id,
                    "item_name": item.name,
                })

                await self._send_to_player(target_id, {
                    "type": "item_received",
                    "item": item.to_dict(),
                    "from_player_id": player_id,
                    "from_username": source.username,
                })

                return {
                    "type": "item_transferred",
                    "item_id": item_id,
                    "to_player_id": target_id,
                }

    async def handle_list_players(self, player_id: str) -> dict:
        online_players = [
            {"player_id": p.player_id, "username": p.username}
            for p in self.players.values()
            if p.websocket is not None
        ]
        return {
            "type": "player_list",
            "players": online_players,
        }

    async def _send_to_player(self, player_id: str, message: dict):
        if player_id in self.connections:
            ws = self.connections[player_id]
            try:
                await ws.send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                pass

    async def _broadcast(self, message: dict, exclude: str = None):
        for pid, ws in self.connections.items():
            if pid != exclude:
                try:
                    await ws.send(json.dumps(message))
                except websockets.exceptions.ConnectionClosed:
                    pass

    async def handle_disconnect(self, player_id: str):
        if player_id in self.connections:
            del self.connections[player_id]

        if player_id in self.players:
            self.players[player_id].websocket = None

            # Cancel any pending trades
            for trade_id, trade in list(self.trades.items()):
                if trade.state in (TradeState.PENDING, TradeState.ACCEPTED):
                    if player_id in (trade.initiator_id, trade.receiver_id):
                        async with self._get_trade_lock(trade_id):
                            trade.state = TradeState.CANCELLED
                            for item_id in trade.initiator_items + trade.receiver_items:
                                if item_id in self.items:
                                    self.items[item_id].locked = False

                            other_id = (
                                trade.receiver_id
                                if player_id == trade.initiator_id
                                else trade.initiator_id
                            )
                            await self._send_to_player(other_id, {
                                "type": "trade_cancelled",
                                "trade_id": trade_id,
                                "reason": "Other player disconnected",
                            })

            self._log_transaction("DISCONNECT", {"player_id": player_id})

            await self._broadcast({
                "type": "player_left",
                "player_id": player_id,
                "username": self.players[player_id].username,
            })

    async def handle_message(self, websocket, player_id: str, raw_message: str) -> dict:
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            return {"type": "error", "message": "Invalid JSON"}

        msg_type = data.get("type")

        handlers = {
            "get_inventory": lambda: self.handle_get_inventory(player_id),
            "list_players": lambda: self.handle_list_players(player_id),
            "initiate_trade": lambda: self.handle_initiate_trade(player_id, data),
            "trade_response": lambda: self.handle_trade_response(player_id, data),
            "update_trade_offer": lambda: self.handle_update_trade_offer(player_id, data),
            "confirm_trade": lambda: self.handle_confirm_trade(player_id, data),
            "cancel_trade": lambda: self.handle_cancel_trade(player_id, data),
            "transfer_item": lambda: self.handle_transfer_item(player_id, data),
        }

        handler = handlers.get(msg_type)
        if handler:
            return await handler()
        else:
            return {"type": "error", "message": f"Unknown message type: {msg_type}"}

    async def connection_handler(self, websocket):
        player_id = None
        try:
            # First message must be login
            raw = await websocket.recv()
            data = json.loads(raw)

            if data.get("type") != "login":
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "First message must be login",
                }))
                return

            response = await self.handle_login(websocket, data)
            await websocket.send(json.dumps(response))

            if response["type"] != "login_success":
                return

            player_id = response["player"]["player_id"]

            async for raw_message in websocket:
                response = await self.handle_message(websocket, player_id, raw_message)
                await websocket.send(json.dumps(response))

        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"Error handling connection: {e}")
            import traceback
            traceback.print_exc()
        finally:
            if player_id:
                await self.handle_disconnect(player_id)


async def main():
    server = GameServer()
    print("MMO Game Server starting on ws://localhost:8765")
    print("Waiting for player connections...")

    async with websockets.serve(server.connection_handler, "localhost", 8765):
        await asyncio.Future()  # Run forever


if __name__ == "__main__":
    asyncio.run(main())